\newcommand{\zapis}{
    {\centering \Large \textbf{VZTLAKOVÁ SÍLA A ARCHIMÉDŮV ZÁKON}\par}
    \vspace{0.5cm}

    \textbf{Vztlaková síla ($F_{vz}$)}
    \begin{itemize}
        \setlength{\itemsep}{2pt}
        \item Síla, která nadlehčuje tělesa ponořená do kapaliny.
        \item Působí \textbf{svisle vzhůru}.
    \end{itemize}

    \vspace{0.3cm}
    {\centering
        \begin{tikzpicture}[scale=1.0]
            % Kádinka
            \draw[thick] (0,0) -- (0,2.5) (3,0) -- (3,2.5);
            \draw[thick] (0,0) -- (3,0);
            % Voda
            \fill[cyan!15] (0,0) rectangle (3,2);
            \draw[cyan, thick] (0,2) -- (3,2);
            % Těleso
            \draw[thick, fill=gray!30] (1,0.5) rectangle (2,1.5);
            % Síly
            \draw[->, very thick, red] (1.5,1) -- (1.5,2.8) node[above] {$\vec{F}_{vz}$};
            \draw[->, very thick, black] (1.5,1) -- (1.5,-0.8) node[below] {$\vec{F}_g$};
            \fill[black] (1.5,1) circle (2pt);
        \end{tikzpicture}\par
    }

    \vspace{0.5cm}
    \textbf{Výpočet vztlakové síly}
    \vspace{-0.2cm}
    \[ F_{vz} = V \cdot \rho_k \cdot g \]
    \vspace{-0.2cm}
    \begin{itemize}
        \setlength{\itemsep}{2pt}
        \item $V$ = objem ponořené části ($\text{m}^3$)
        \item $\rho_k$ = hustota kapaliny ($\text{kg/m}^3$)
        \item $g$ = tíhové zrychlení ($\approx 10\ \text{m/s}^2$)
    \end{itemize}

    \vspace{0.5cm}
    \textbf{Archimédův zákon}
    \begin{quote}
        \textit{Těleso ponořené do kapaliny je nadlehčováno vztlakovou silou. Ta je stejně velká, jako gravitační síla kapaliny, kterou tím tělesem vytlačím.}
    \end{quote}

    \vspace{0.5cm}
    \textbf{Chování těles v kapalině}\\
    Závisí na porovnání hustoty tělesa ($\rho_t$) a hustoty kapaliny ($\rho_k$).

    \vspace{0.5cm}
    {\centering
        \begin{tikzpicture}[scale=0.8]
            % Potápí se
            \draw[thick] (0,0) |- (2,0) |- (2,3) (0,0) -- (0,3);
            \fill[cyan!15] (0,0) rectangle (2,2.5);
            \draw[cyan, thick] (0,2.5) -- (2,2.5);
            \draw[thick, fill=gray!50] (0.5,0) rectangle (1.5,1);
            \node at (1,-0.6) {\textbf{Potápí se}};
            \node at (1,-1.4) {$\rho_t > \rho_k$};
            \node at (1,-2.2) {$F_g > F_{vz}$};

            % Vznáší se
            \begin{scope}[shift={(4.5,0)}]
                \draw[thick] (0,0) |- (2,0) |- (2,3) (0,0) -- (0,3);
                \fill[cyan!15] (0,0) rectangle (2,2.5);
                \draw[cyan, thick] (0,2.5) -- (2,2.5);
                \draw[thick, fill=gray!50] (0.5,0.8) rectangle (1.5,1.8);
                \node at (1,-0.6) {\textbf{Vznáší se}};
                \node at (1,-1.4) {$\rho_t = \rho_k$};
                \node at (1,-2.2) {$F_g = F_{vz}$};
            \end{scope}

            % Plove
            \begin{scope}[shift={(9,0)}]
                \draw[thick] (0,0) |- (2,0) |- (2,3) (0,0) -- (0,3);
                \fill[cyan!15] (0,0) rectangle (2,2.5);
                \draw[cyan, thick] (0,2.5) -- (2,2.5);
                \draw[thick, fill=gray!50] (0.5,2) rectangle (1.5,3);
                \node at (1,-0.6) {\textbf{Plove}};
                \node at (1,-1.4) {$\rho_t < \rho_k$};
                \node at (1,-2.2) {$F_g = F_{vz}$};
            \end{scope}
        \end{tikzpicture}\par
    }
}

